<div class="d-flex justify-content-between align-items-center mb-4"><div><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Trust & safety</p><h1 class="h2 mb-0">Review Moderation</h1></div><a class="btn btn-outline-secondary" href="<?= e(url('/admin')) ?>">Dashboard</a></div>
<?php if($reviews===[]):?><div class="archive-card p-4 text-muted">No marketplace reviews.</div><?php else:?><div class="row g-3"><?php foreach($reviews as $review):?><div class="col-12"><div class="archive-card p-3"><div class="row g-3"><div class="col-lg-8"><strong><?= e(str_repeat('★',(int)$review['rating'])) ?><?= e(str_repeat('☆',5-(int)$review['rating'])) ?></strong> <span class="badge text-bg-light"><?= e($review['status']) ?></span><div class="small text-muted">Verified order #<?= e((string)$review['order_id']) ?> · <?= e($review['reviewer_username']) ?> reviewing <?= e($review['seller_username']) ?></div><div class="mt-2"><?= nl2br(e($review['body'])) ?></div></div><div class="col-lg-4"><form method="post" action="<?= e(url('/admin/reviews/moderate?id='.(int)$review['id'])) ?>"><select class="form-select form-select-sm mb-2" name="status"><option value="published" <?= $review['status']==='published'?'selected':'' ?>>Published</option><option value="hidden" <?= $review['status']==='hidden'?'selected':'' ?>>Hidden</option></select><textarea class="form-control form-control-sm" name="moderation_notes" maxlength="1000" rows="2" placeholder="Required when hiding"><?= e($review['moderation_notes']??'') ?></textarea><button class="btn btn-sm btn-archive mt-2">Save</button></form></div></div></div></div><?php endforeach;?></div><?php endif;?>
